```rust
/// M16: OPEN a model session — kernel-mediated (NOT a dispatch method: it needs
/// the Router; the agent_channel_connect/agent_block_create precedent). Resolves
/// the model: scheme, mints an ObjKind::ModelSession bound to the registered
/// backend WITH INVOKE_MODEL|READ into t's OWN table. Unknown scheme -> clean
/// BadCap (NEVER a panic). `None` only if t is not an agent.
pub fn agent_model_open(t: Task, scheme: &str) -> Option<(u32, u64)> {
    let slot = t.raw(); if slot >= MAX_TASKS { return None; }
    let (model, backend) = match infer::resolve(scheme) {
        Some(x) => x, None => return Some((caps::SysStatus::BadCap as u32, 0)),
    };
    let rights = caps::Rights::INVOKE_MODEL.union(caps::Rights::READ);
    let ap = AGENTS.slot(slot).as_mut()?;
    match ap.table.mint_model_session(rights, infer::ModelSession { backend, model }) {
        Some(h) => Some((caps::SysStatus::Ok as u32, h.raw())),
        None => Some((caps::SysStatus::ObjFull as u32, 0)),
    }
}
/// M16: drive a numbered, cap-checked caps::dispatch against t's OWN table (the
/// agent_block_dispatch clone) — the self-test door for M_MODEL_INVOKE + the
/// session-handle NARROW. Every call routes the M11 chokepoint.
pub fn agent_model_dispatch(t: Task, method: u32, handle: caps::Handle, a0: u64) -> Option<(u32, u64)> {
    let slot = t.raw(); if slot >= MAX_TASKS { return None; }
    let ap = AGENTS.slot(slot).as_mut()?;
    let args = caps::SyscallArgs { method, handle, args: [a0, 0, 0, 0] };
    let ret = caps::dispatch(&mut ap.table, &args);
    Some((ret.status as u32, ret.value))
}
```
(AGENTS.slot().as_mut() is the EXISTING pattern agent_block_create already uses — NOT new unsafe.)
