design.selftest:
Insert in kernel\src\main.rs BETWEEN the `M15: blocks OK` marker (~line 1887) and the final `tb_hal::halt()` (~1890) that ends rust_main. Reuse agent_c (MANIFEST_A) / agent_d already in scope — no extra MAX_TASKS slots. Pattern = the M13/M14/M15 blocks verbatim. Note MANIFEST_A/B OMIT INVOKE_MODEL, so the success path's right comes from the FACADE grant (kernel-mediated), and the Denied path narrows it away — proving the gate still bites.

```rust
// --- M16: LLM-agnostic inference bridge — the model: scheme + ModelSession -----
{
    use tb_hal::caps; use tb_hal::caps::Handle;
    fn m16_fail(why: &str) -> ! {
        tb_hal::serial_write_str("M16: FAIL "); tb_hal::serial_write_str(why);
        tb_hal::serial_write_str("\n"); tb_hal::halt()
    }
    let ok = caps::SysStatus::Ok as u32; let den = caps::SysStatus::Denied as u32;
    let badcap = caps::SysStatus::BadCap as u32; let badmethod = caps::SysStatus::BadMethod as u32;
    const PROMPT: u64 = 0x1234_5678; let expect = PROMPT ^ 0xA110_C0DE;

    // (1) PARSE: a model: URI parses; a non-model: scheme cleanly rejects.
    if tb_hal::infer::parse_scheme("model:local/llama3").is_none() { m16_fail("parse model:local/llama3 None"); }
    if tb_hal::infer::parse_scheme("memory:x").is_some()          { m16_fail("parse memory:x was Some"); }

    // (2) OPEN + INVOKE: model:mock/echo -> session WITH INVOKE_MODEL; deterministic.
    let (s, sraw) = tb_hal::agent_model_open(agent_c, "model:mock/echo").unwrap_or((badcap, 0));
    if s != ok { m16_fail("open model:mock/echo not Ok"); }
    let sess = Handle::from_raw(sraw);
    let (s, resp) = tb_hal::agent_model_dispatch(agent_c, caps::M_MODEL_INVOKE, sess, PROMPT).unwrap_or((badcap, 0));
    if s != ok || resp != expect { m16_fail("invoke not deterministic Ok"); }

    // (3) BACKEND-AGNOSTIC: a 2nd model: name, SAME contract, SAME response — same agent code.
    let (s, s2raw) = tb_hal::agent_model_open(agent_c, "model:local/llama3").unwrap_or((badcap, 0));
    if s != ok { m16_fail("open model:local/llama3 not Ok"); }
    let sess2 = Handle::from_raw(s2raw);
    let (s, resp2) = tb_hal::agent_model_dispatch(agent_c, caps::M_MODEL_INVOKE, sess2, PROMPT).unwrap_or((badcap, 0));
    if s != ok || resp2 != expect { m16_fail("backend swap changed the contract"); }

    // (4) DENIED: NARROW the session to drop INVOKE_MODEL (mask 0), then invoke (M15 no_read precedent).
    let (s, nraw) = tb_hal::agent_model_dispatch(agent_c, caps::M_HANDLE_NARROW, sess, 0).unwrap_or((badcap, 0));
    if s != ok { m16_fail("narrow session to empty rights failed"); }
    let no_inv = Handle::from_raw(nraw);
    let (s, _) = tb_hal::agent_model_dispatch(agent_c, caps::M_MODEL_INVOKE, no_inv, PROMPT).unwrap_or((ok, 0));
    if s != den { m16_fail("invoke without INVOKE_MODEL not Denied"); }

    // (5) UNKNOWN scheme: clean closed error, never a panic.
    let (s, _) = tb_hal::agent_model_open(agent_c, "model:vendor/ghost").unwrap_or((ok, 0));
    if s != badcap { m16_fail("unknown model: scheme not BadCap"); }

    // (6) NON-SESSION: M_MODEL_INVOKE on a Generic cap minted WITH INVOKE_MODEL -> BadCap (payload-None branch).
    let gen = tb_hal::agent_mint_generic(agent_c, caps::Rights::INVOKE_MODEL)
        .unwrap_or_else(|| m16_fail("mint generic INVOKE_MODEL cap failed"));
    let (s, _) = tb_hal::agent_model_dispatch(agent_c, caps::M_MODEL_INVOKE, gen, PROMPT).unwrap_or((ok, 0));
    if s != badcap { m16_fail("M_MODEL_INVOKE on a non-session not BadCap"); }

    // (7) closed-set probe: an unknown method stays BadMethod (M_BLOCK_READ=31 is the highest).
    let (s, _) = tb_hal::agent_model_dispatch(agent_c, 33, sess, 0).unwrap_or((ok, 0));
    if s != badmethod { m16_fail("unknown method 33 not BadMethod"); }

    tb_hal::serial_write_str("model: parse+route + INVOKE_MODEL gate + backend-agnostic + lifecycle\n");
}
tb_hal::serial_write_str("M16: infer OK\n"); // <-- the M16 DoD marker (ROADMAP-V2.md:62)
```
Every assert routes caps::dispatch against the agent's OWN table (the M11 chokepoint), proving parse+route+gate+contract+lifecycle. Timer is already disarmed (single-core, interrupts masked) here — the discipline the safe payloads rely on.
